/*
 * SHARED STRUCTURED LOGGER
 * ─────────────────────────────────────────────────────────────────
 * Accepts a log envelope and fans out to all configured sinks.
 *
 * Expected input schema:
 * {
 *   level:      'DEBUG' | 'INFO' | 'WARN' | 'ERROR' | 'FATAL'
 *   workflow:   string          // calling workflow name
 *   event:      string          // machine-readable event code
 *   message:    string          // human-readable description
 *   traceId:    string          // propagated trace id
 *   data?:      object          // arbitrary structured context
 *   error?:     { message, stack, code }
 *   durationMs?: number
 * }
 */

const raw = $input.first().json;

// ── Defaults & validation ──────────────────────────────────────────
const VALID_LEVELS = ['DEBUG', 'INFO', 'WARN', 'ERROR', 'FATAL'];
const level = VALID_LEVELS.includes(raw.level) ? raw.level : 'INFO';

const envelope = {
  // Core identity
  traceId:    raw.traceId    || `tr-${Date.now()}-${Math.random().toString(36).slice(2,8)}`,
  timestamp:  new Date().toISOString(),
  level,

  // Source
  workflow:   raw.workflow   || 'unknown-workflow',
  event:      raw.event      || 'unspecified',
  message:    raw.message    || '',

  // Payload
  data:       raw.data       || {},
  error:      raw.error      || null,
  durationMs: raw.durationMs || null,

  // Runtime metadata
  env:        process.env.NODE_ENV || 'production',
  host:       process.env.N8N_HOST || 'n8n',
};

// ── Severity routing flags ─────────────────────────────────────────
const shouldAlertSlack  = ['WARN', 'ERROR', 'FATAL'].includes(level);
const shouldWriteSheets = true;   // always write every log entry
const isHighSeverity    = ['ERROR', 'FATAL'].includes(level);

// ── Console sink (always — captured by log aggregators) ───────────
console.log(JSON.stringify(envelope));

return [{
  json: {
    envelope,
    routing: {
      shouldAlertSlack,
      shouldWriteSheets,
      isHighSeverity
    }
  }
}];

// Format Slack alert based on severity level
const { envelope, routing } = $input.first().json;

const EMOJI = {
  WARN:  '⚠️',
  ERROR: '🔴',
  FATAL: '💀'
};

const COLOR = {
  WARN:  '#FFA500',
  ERROR: '#CC0000',
  FATAL: '#000000'
};

const emoji = EMOJI[envelope.level] || '📋';
const color = COLOR[envelope.level] || '#36A64F';

// Build Slack Block Kit payload
const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `${emoji} [${envelope.level}] ${envelope.event}`, emoji: true }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Workflow:*\n${envelope.workflow}` },
      { type: 'mrkdwn', text: `*Level:*\n${envelope.level}` },
      { type: 'mrkdwn', text: `*Trace ID:*\n\`${envelope.traceId}\`` },
      { type: 'mrkdwn', text: `*Time:*\n${envelope.timestamp}` }
    ]
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Message:*\n${envelope.message}` }
  }
];

if (envelope.error) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*Error:*\n\`\`\`${JSON.stringify(envelope.error, null, 2).slice(0, 500)}\`\`\`` }
  });
}

if (envelope.durationMs) {
  blocks.push({
    type: 'context',
    elements: [{ type: 'mrkdwn', text: `Duration: ${envelope.durationMs}ms` }]
  });
}

blocks.push({ type: 'divider' });

return [{
  json: {
    ...($input.first().json),
    slackPayload: {
      channel: routing.isHighSeverity ? '#oncall-alerts' : '#automation-logs',
      blocks,
      text: `[${envelope.level}] ${envelope.workflow}: ${envelope.message}`,
      attachments: [{ color }]
    }
  }
}];
